  if (!token) return res.status(400).json({ active: false });

  try {
    const payload = jwt.verify(token, JWT_SECRET, { algorithms: ['HS256'] });
    if (payload.typ !== 'access') return res.json({ active: false });

    const active = await isAccessTokenJtiActive(payload.jti);
    if (!active) return res.json({ active: false });

    return res.json({
      active: true,
      iss: payload.iss,
      aud: payload.aud,
      sub: payload.sub,
      scope: payload.scope || '',
      exp: payload.exp,
      iat: payload.iat,
      jti: payload.jti,
    });
  } catch {
    return res.json({ active: false });
  }
